import android.content.Context;
import android.content.SharedPreferences;

public class LoginManager {
    private static final String PREFS_NAME = "LoginPrefs";
    private static final String KEY_EMAIL = "email";
    private static final String KEY_AUTH_TOKEN = "authToken";

    public void saveCredentials(Context context, String email, String authToken) {
        SharedPreferences prefs = context.getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE);
        prefs.edit().putString(KEY_EMAIL, email).apply();
        prefs.edit().putString(KEY_AUTH_TOKEN, authToken).apply();
    }

    public boolean loadCredentials(Context context) {
        SharedPreferences prefs = context.getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE);
        String email = prefs.getString(KEY_EMAIL, null);
        String authToken = prefs.getString(KEY_AUTH_TOKEN, null);

        if (email != null && authToken != null) {
            return true;
        } else {
            return false;
        }
    }

    public void clearCredentials(Context context) {
        SharedPreferences prefs = context.getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE);
        prefs.edit().clear().apply();
    }
}